// ===============================
// ITEM ATUAL
// ===============================
const item = $input.item.json;
// ===============================
// PARSE DOS DADOS META
// ===============================
let dadosMeta;
try {
  dadosMeta =
    typeof item.dados_meta === 'string'
      ? JSON.parse(item.dados_meta)
      : item.dados_meta;
} catch (e) {
  throw new Error('dados_meta não é um JSON válido');
}
// ===============================
// SEGURANÇAS
// ===============================
if (!dadosMeta || !Array.isArray(dadosMeta.parametros)) {
  throw new Error('dados_meta.parametros não é um array');
}
if (!dadosMeta.template_whatsapp) {
  throw new Error('template_whatsapp não informado');
}
// ===============================
// MONTA BODY PARAMETERS
// ===============================
const bodyParameters = dadosMeta.parametros.map(p => {
  if (p.source === 'nome') {
    return {
      type: 'text',
      text: String(item.name || '')
    };
  }
  if (p.source === 'legenda') {
    return {
      type: 'text',
      text: String(p.value || '')
        .replace(/\n\n/g, ' | ')
        .replace(/\n/g, ' ')
        .replace(/\t/g, ' ')
        .replace(/ {5,}/g, '    ')
    };
  }
  // fallback de segurança
  return {
    type: 'text',
    text: ''
  };
});
// ===============================
// COMPONENTS
// ===============================
const components = [];
// HEADER (mídia)
if (
  dadosMeta.media_type &&
  dadosMeta.media_type !== 'none' &&
  dadosMeta.media_url
) {
  components.push({
    type: 'header',
    parameters: [
      {
        type: dadosMeta.media_type,
        [dadosMeta.media_type]: {
          link: dadosMeta.media_url
        }
      }
    ]
  });
}
// BODY
components.push({
  type: 'body',
  parameters: bodyParameters
});
// ===============================
// RETORNO FINAL (META API)
// ===============================
return {
  json: {
    messaging_product: 'whatsapp',
    to: String(item.phone_normalized),
    type: 'template',
    template: {
      name: dadosMeta.template_whatsapp,
      language: {
        code: dadosMeta.language || 'pt_BR'
      },
      components
    }
  }
};

// ===============================
// DADOS DE ENTRADA
// ===============================
// Mensagens diárias (AGORA É ARRAY)
const mensagens = $('Merge').all();
// Linha do template vinda do Supabase
const template = $input.item.json;
// ===============================
// SEGURANÇAS
// ===============================
if (!template.variables || !Array.isArray(template.variables)) {
  throw new Error('Template sem array de variables no Supabase');
}
// ===============================
// PROCESSAR CADA CONTATO
// ===============================
const resultados = mensagens.map(item => {
  const mensagem = item.json;
  // ===============================
  // VALIDA PHONE NUMBER
  // ===============================
  if (!mensagem.dados_meta?.phone_number_id_meta) {
    throw new Error('phone_number_id_meta não encontrado no Switch1');
  }
  const phoneId = mensagem.dados_meta.phone_number_id_meta;
  // ===============================
  // QUEBRA DA LEGENDA
  // ===============================
  const blocosLegenda = (mensagem.legenda_whatsapp || '')
    .split(/\n\s*\n/)
    .map(t => t.trim())
    .filter(Boolean);
  // ===============================
  // VARIÁVEIS DO TEMPLATE
  // ===============================
  const variables = template.variables;
  const totalVars = variables.length;
  // ===============================
  // MONTA PARAMETROS
  // ===============================
  const parametros = [];
  let legendaCursor = 0;
  for (let i = 0; i < totalVars; i++) {
    const varName = variables[i];
    if (varName === 'nome_usuario') {
      parametros.push({
        type: 'text',
        source: 'nome'
      });
    } else if (varName === 'resumo_completo') {
      // Pega o texto inteiro da célula sem dividir em blocos
      parametros.push({
        type: 'text',
        source: 'legenda',
        value: mensagem.legenda_whatsapp || ''
      });
    } else {
      parametros.push({
        type: 'text',
        source: 'legenda',
        value: blocosLegenda[legendaCursor] || ''
      });
      legendaCursor++;
    }
  }
  // ===============================
  // DEFINE MÍDIA (SE EXISTIR)
  // ===============================
  let media_type = 'none';
  let media_url = null;
  if (template.media_type && template.media_type !== 'none') {
    media_type = template.media_type;
    media_url = template.media_url || mensagem.imagem1 || null;
  }
  // ===============================
  // RETORNO PARA ESTE CONTATO
  // ===============================
  return {
    json: {
      ...mensagem, // mantém todos os dados do contato
      phone_number_id_meta: phoneId,
      dados_meta: {
        template_whatsapp: template.meta_template_name,
        meta_template_id: template.meta_template_id,
        language: template.language || 'pt_BR',
        media_type,
        media_url,
        parametros
      }
    }
  };
});
return resultados;

